var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지난 날 발생했던 침식사태 이후 특이증상을 앓고 있는 침식증후군 환자들이 급증하고 있습니다.</color>","JPN":"<color=#ffd34c>先日発生した侵食事態以後、特異症状を訴える侵食症候群の患者が急増しています。</color>","ENG":"<color=#ffd34c>Since the last Corruption disaster, the number of Corruption Syndrome patients is rapidly increasing.</color>","TWN":"<color=#ffd34c>先前發生侵蝕事件後，有特殊症狀的侵蝕症候群患者迅速增加中。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>원인은 침식체에게 직접적으로 공격받거나 침식지대 내 상처를 통한 감염입니다.</color>","JPN":"<color=#ffd34c>原因は侵食体の直接攻撃、もしくは侵食地帯内で負った傷による感染です。</color>","ENG":"<color=#ffd34c>The patients are usually victims of C.O. attacks, or sicked due to wounds inflicted in the Corrupted Area.</color>","TWN":"<color=#ffd34c>原因是由於直接受到侵蝕體的攻擊，或是在傷口侵蝕地區內受到感染。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신종 침식증후군 환자들은 급격한 세포 노화와 고통을 호소한다는 공통점이 있다고 합니다.</color>","JPN":"<color=#ffd34c>新型侵食症候群の患者は急激な細胞の老化や痛みを訴えるという共通点があるそうです。</color>","ENG":"<color=#ffd34c>These new Corruption Syndrome patients are suffering from rapid cell aging and severe pain.</color>","TWN":"<color=#ffd34c>新型侵蝕症候群患者的共同點是，疾速的細胞老化和痛苦。</color>"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아직까지 전염 사례는 보고되지 않았지만, 유사한 증상의 환자가 있을 경우 절대 접촉해선 안 된다며 도시관리국의 당부가…</color>","JPN":"<color=#ffd34c>伝染事例はまだ報告されていませんが、類似症状の患者がいる場合、\\n絶対に接触してはならないと都市管理局からの要請が……</color>","ENG":"<color=#ffd34c>According to City Management, no contagion case is reported yet, but it is recommended not to be in contact with those who show similar symptoms...</color>","TWN":"<color=#ffd34c>雖然目前尚未獲報有傳染的案例，但城市管理局建議，若有類似症狀的患者，千萬不要和他們接觸…</color>"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"그러면 한동안 계속 입원해야 하는 건가요?","JPN":"それじゃあ、しばらく入院する必要があるんですか？","ENG":"So she’ll be staying in the hospital for a while?","TWN":"那需要住院一段時間嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"현재로선 그렇습니다.","JPN":"現状はそうです。","ENG":"Yes, for now.","TWN":"目前是這樣沒錯。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"그럼 퇴원은 언제쯤 할 수 있겠습니까?","JPN":"では、退院はいつ頃になりそうですか？","ENG":"When will she be discharged?","TWN":"那什麼時候可以出院？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"곧 시험도 있고, 대회도 있는데…","JPN":"もう少しでテスト期間に入りますし、大会もあるのに……","ENG":"She has an exam and a competition to participate in...","TWN":"因為馬上就要考試了，而且還有比賽……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"그것 때문에 정말 노력했던 학생이거든요.","JPN":"そのために本当に努力してきた子なんです。","ENG":"She’s been working so hard for that.","TWN":"她很努力預備呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"지금까지 학계에 알려진 적 없는 증상입니다.","JPN":"今まで学界で報告されたことのない症状です。","ENG":"We’ve never seen something like this before.","TWN":"她的症狀目前在醫學界也沒有相關前例。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"환자분의 상태를 솔직하게 말씀드리자면.","JPN":"患者の状態を正直に申し上げますと……","ENG":"For now, once the patient is diagnosed with Corruption Syndrome...","TWN":"坦白說，以患者目前的狀況……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"증상이 침식증후군으로 분류된 시점에서, 연명치료가 최선일 것으로 보고 있습니다.","JPN":"症状が侵食症候群に分類された時点で、延命治療が最善だと考えています。","ENG":"All we can do for her is provide life sustaining treatments.","TWN":"在她的症狀被歸類爲侵蝕症候群後，我們能做的就只有維生醫療。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 선생님.","JPN":"あっ、先生。","ENG":"Teacher.","TWN":"老師！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이로하는 어떻다던가요?","JPN":"いろはの様子はどうですか？","ENG":"How is Iroha?","TWN":"伊呂波情況如何？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"무슨 병인지 모른다고 병문안 자체를 막다니, 사람들도 참 과민반응이라니까요.","JPN":"何の病気か不明だからってお見舞いを禁止するのは、少し過剰ですよね。","ENG":"I think they are just overreacting, not allowing visitors just because they don’t know what’s going on.","TWN":"因為不確定病情就阻止人家來探病，大家會不會太反應過度？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"…그게 말이다.","JPN":"……そうだな。","ENG":"... Minato.","TWN":"…那是因為。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"상태가… 별로 좋지 않은 모양이다.","JPN":"具合が……あまりよくないようだ。","ENG":"Iroha is... not well.","TWN":"情況…似乎不太樂觀。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"이로하는 이제부터 격리병동으로 옮긴다더구나.","JPN":"いろはをこれから隔離病棟に移すらしい。","ENG":"They are moving her to an isolation ward.","TWN":"醫生說要將伊呂波轉到隔離病房。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};